import{_ as r}from"./nyalra_kb-7135827b.js";import{_ as p}from"./nyalra_no_mono-8344e451.js";import{_ as c,W as s,X as i,Y as _,Z as e,$ as t,a1 as a,a2 as m,a0 as d,C as o}from"./framework-91490e6a.js";const b={},g=e("figure",null,[e("img",{src:r,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),f={href:"https://tree-novel.com/works/episode/6c75b6ebe60f660432c23b623f4d9eb2.html",target:"_blank",rel:"noopener noreferrer"},h=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),k=d('<hr><p>我变得令人意外地不擅长「酒会」这种行为了。虽然我本来就不怎么喜欢，但最近我渐渐地希望尽量避开它。</p><p>原因可能是频率增加了。</p><p>自从游戏发布以来，我不得不与各种各样的人交往。并没有特别讨厌某个人，而为了和某个人建立更加亲密的关系，参加酒会是必要的，但每次社交活动都会耗费我的精力。</p><p>社交活动本质上是虚伪的。社交辞令是夸大其词和谎言，是为了顺利进行当场的社交而存在的。这令人感到不适。陈于表面的对话几乎没有任何实质性的内容。我理解社交辞令对于巩固人际关系的基础是必要的。但令人不适的仍然是不适的。</p><p>比起自己说出来，被别人说出来会更令人难受。像是「你的游戏真棒！」或「你正在写文章对吧！」。因为今后可能会成为工作对象，所以在会面初期会被先用这种水平的话题展开对话，这令我尴尬。尽管我知道对方不是故意的，但这还是会让我感到疲惫，因为必须数十次·数百次地反复地做出相同的回应。感觉就像是一个循环。</p><p>因此，当我与创作者等人会面时，我决定只谈我真正感兴趣的事情。例如，如果我遇到了音乐家，我会提到他们作曲中我喜欢的歌曲，或者询问他们工作中我感兴趣的方面。彻底避免了俗套的交流。只有在对方的作品真的令我印象深刻时，我才会露出笑容说「○○真的很好！」。人们不知为何就是能够感受到对方是否真心喜欢他。因此，我会传达这一点。</p><p>现在，由于我的游戏表现出色，当我在场时，会产生「必须称赞」的氛围。当然，受到赞扬是令人高兴的，但在场的人都有自己的作品和贡献，不必过分夸奖我。我没问题。只需简单地介绍最近的情况，然后谈论喜欢的动画、漫画，或最近看的电影等。这是最好的方式。即使是与工作伙伴会面，从这些话题中也更有可能看到一些东西。甚至可以说「我不喜欢这个作品！」。如果有明确的意见，那会是个好话题。比起只是为了「感到亲近」而毫无意义地维持会话，这样更好。</p><p>如果可能的话，我不想撒谎或夸大其词。我只想把自己的心情说清楚。我的朋友们说，「我不太了解奈亚拉你的游戏。这不重要。比起这个，下周我们去公园吧。」就是这种态度。我希望他们就是这样。我不想每次都从「尊敬的○○先生/女士，我听说过您的辉煌业绩！」这样的话题开始对话。</p><p>即便如此，因为酒精的效果而大声喧哗、拍手叫好……这种状态我无法做到。一直保持安静就好。既然本来就是为了交谈，喝酒完全就没有必要吧。没有液体，我也可以和你谈论动漫和漫画，感到愉快。不需要刻意提高声音，你的幽默笑话也会让我开心。不必强迫互相称赞，只要喜欢相同的事物和共同的目标，我们就是朋友。</p><p>我一直在考虑这些事情。尽管如此，人们仍然邀请我参加酒会，每次我都会坐下来，抱怨着说：「唉，真吵啊，你们这些家伙。」大家都取笑我，说：「这家伙真麻烦！」</p><p>虽然不喜欢，但与人在一起确实让我感到安心。也许大家都有这样的感觉吧。</p><hr><p><img src="'+p+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/dd571084ee06557c5fb1ebd1f7843687.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/88aa776bd007e271feb6f0137d1d4abc.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/a05e6468441bbad18a0cb325a0b11a1c.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/8ec0e092c5467a80a9b0fbbe7ac5d713.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【专栏编辑给我买的钢笔】当我提到我喜欢钢笔时，这个专栏的编辑为我的生日送了一支钢笔给我。我感到非常高兴。除了这个专栏，我还在进行其他项目，所以每次写字都希望能感受到一些压力。虽然有点害怕，但我会努力的。</p></blockquote>',15);function u(y,v){const l=o("ExternalLinkIcon"),n=o("RouterLink");return s(),i("div",null,[_(" more "),g,e("p",null,[t("原文链接："),e("a",f,[t("第25回／飲み会嫌い"),a(l)])]),e("blockquote",null,[h,e("p",null,[a(n,{to:"/posts/Translate/nyalra_kb_24.html"},{default:m(()=>[t("【奈亚拉面壁自语】第24回｜咳嗽仍孤身一人【230502】")]),_:1})])]),k])}const V=c(b,[["render",u],["__file","nyalra_kb_25.html.vue"]]);export{V as default};
